&lt;p&gt;संधीचे मुख्य ३ प्रकार पडतात.&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;स्वर संधी&lt;/li&gt;
	&lt;li&gt;व्यंजन&amp;nbsp; संधी&lt;/li&gt;
	&lt;li&gt;विसर्ग संधी&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;strong&gt;स्वर संधी- &lt;/strong&gt;जवळ येणारे वर्ण जर स्वर असतील, तर त्यास &amp;lsquo;स्वरसंधी&amp;#39; असे म्हणतात.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;नियम-&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;स्वर संधीचेही बरेच प्रकार पडतात. त्यातीलच योग्य पर्याय असलेला प्रकार आपण पाहूयात.&lt;/li&gt;
	&lt;li&gt;स्वर संधीतील एक नियम असे सांगतो की &amp;#39;अ&amp;#39; किंवा &amp;lsquo;आ&amp;#39; पुढे&amp;nbsp; &amp;#39;अ&amp;#39; किंवा &amp;lsquo;आ&amp;#39; स्वर आल्यास दोहोंबद्दल &amp;lsquo;आ&amp;#39; येतो, पर + अधीन&amp;nbsp; यातील पर या शब्दातील &amp;#39;अ&amp;#39; व&amp;nbsp; अधीन या शब्दातील &amp;lsquo;अ&amp;#39; यांची संधी होऊन दोहोंबद्दल &amp;#39;आ&amp;#39; येईल.&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;उदा.&lt;/strong&gt;&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;ग्रंथ + आलय = ग्रंथालय&lt;/li&gt;
	&lt;li&gt;विद्या + आलय = विद्यालय&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;वनिता + आश्रम =&amp;nbsp;&lt;span style=&quot;&quot;&gt;वनिताश्रम&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;अशाप्रकारे&amp;nbsp;&lt;span style=&quot;&quot;&gt;वनिताश्रम या पदामध्ये&amp;nbsp;&lt;strong&gt;स्वर संधी&lt;/strong&gt; आहे.&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;उत्तर -&amp;nbsp;&lt;/span&gt;मंत्रालय या शब्दाचा विग्रह मंत्री + आलय असा होईल.&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;#39;मंत्रालय&amp;#39; या शब्दाचा योग्य आणि प्रचलित विग्रह मंत्री + आलय असा आहे, कारण &amp;#39;आलय&amp;#39; म्हणजे घर किंवा निवासस्थान, आणि &amp;#39;मंत्रालय&amp;#39; म्हणजे मंत्र्यांचे ठिकाण किंवा मंत्र्यांचे निवासस्थान/कार्यालय&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;संधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जोडशब्द तयार करताना पहिल्या शब्दातील शेवटचा वर्ण व दुसऱ्या शब्दातील पहिला वर्ण हे एकमेकांमध्ये मिसळतात व त्या दोन्हीबद्दल एक वर्ण तयार होतो. वर्णाच्या अशा एकत्र होण्याच्या प्रकाराला&amp;nbsp;संधी&amp;nbsp;असे म्हणतात.&lt;/p&gt;

&lt;p&gt;संधीचे&amp;nbsp;&lt;strong&gt;तीन&lt;/strong&gt;&amp;nbsp;प्रकार आहेत.&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;स्वरसंधी&lt;/li&gt;
	&lt;li&gt;व्यंजनसंधी&lt;/li&gt;
	&lt;li&gt;विसर्गसंधी&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;strong&gt;स्वरसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकमेकांच्या शेजारी येणारे वर्ण हे जर स्वरांनी जोडले असतील तर त्यांना स्वरसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;स्वर + स्वर असे याचे&amp;nbsp;स्वरूप असते.​&amp;nbsp;उदा. विद्या + अर्थी = विद्यार्थी&amp;nbsp; (आ + अ = आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;व्यंजनसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जवळ जवळ येणाऱ्या या दोन वर्णांपैकी दोन्ही वर्ण व्यंजने असतील किंवा पहिला वर्ण व्यंजन व दुसरा वर्ण स्वर असेल तर त्याला व्यंजनसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;व्यंजन&amp;nbsp;+&amp;nbsp;व्यंजन&amp;nbsp;किंवा स्वर&amp;nbsp;असे त्याचे स्वरूप असते.&amp;nbsp;&amp;nbsp;उदा. सत्&amp;nbsp;+ आचार = सदाचार (त्&amp;nbsp;+&amp;nbsp;आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;विसर्गसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकत्र येणाऱ्या वर्णातील पहिला विसर्ग व दुसरा वर्ण व्यंजन किंवा स्वर असेल तर तेव्हा त्यास विसर्ग संधी असे म्हणतात.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;विसर्ग + व्यंजन किंवा विसर्ग + स्वर असे त्याचे स्वरूप असते. उदा. नि: + अंतर = निरंतर&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;उत्तर -&lt;/strong&gt;&amp;nbsp;&lt;span style=&quot;&quot;&gt;मतैक्य&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;या शब्दाचा&lt;/span&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;विग्रह&lt;/span&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;मत + ऐक्य&lt;/strong&gt; असा होईल.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;मतैक्य&amp;nbsp;&lt;/span&gt;हे&amp;nbsp;&lt;strong&gt;वृद्धयादेश&lt;/strong&gt;&amp;nbsp;स्वरसंधीचे उदाहरण आहे.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;मतैक्य =&amp;nbsp;मत + ऐक्य (अ + ऐ = ऐ)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;वृद्धयादेश&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;&lt;strong&gt;अ/आ + ए/ऐ = ऐ&lt;/strong&gt;&amp;nbsp;होतो व&amp;nbsp;&lt;strong&gt;अ/आ + ओ/औ&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;=&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;औ&lt;/strong&gt;&amp;nbsp;होतो याला&amp;nbsp;वृद्धयादेश असे म्हणतात.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;संधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जोडशब्द तयार करताना पहिल्या शब्दातील शेवटचा वर्ण व दुसऱ्या शब्दातील पहिला वर्ण हे एकमेकांमध्ये मिसळतात व त्या दोन्हीबद्दल एक वर्ण तयार होतो. वर्णाच्या अशा एकत्र होण्याच्या प्रकाराला&amp;nbsp;संधी&amp;nbsp;असे म्हणतात.&lt;/p&gt;

&lt;p&gt;संधीचे&amp;nbsp;&lt;strong&gt;तीन&lt;/strong&gt;&amp;nbsp;प्रकार आहेत.&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;स्वरसंधी&lt;/li&gt;
	&lt;li&gt;व्यंजनसंधी&lt;/li&gt;
	&lt;li&gt;विसर्गसंधी&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;strong&gt;स्वरसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकमेकांच्या शेजारी येणारे वर्ण हे जर स्वरांनी जोडले असतील तर त्यांना स्वरसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;स्वर + स्वर असे याचे&amp;nbsp;स्वरूप असते.​&amp;nbsp;उदा. विद्या + अर्थी = विद्यार्थी&amp;nbsp; (आ + अ = आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;व्यंजनसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जवळ जवळ येणाऱ्या या दोन वर्णांपैकी दोन्ही वर्ण व्यंजने असतील किंवा पहिला वर्ण व्यंजन व दुसरा वर्ण स्वर असेल तर त्याला व्यंजनसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;व्यंजन&amp;nbsp;+&amp;nbsp;व्यंजन&amp;nbsp;किंवा स्वर&amp;nbsp;असे त्याचे स्वरूप असते.&amp;nbsp;&amp;nbsp;उदा. सत्&amp;nbsp;+ आचार = सदाचार (त्&amp;nbsp;+&amp;nbsp;आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;विसर्गसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकत्र येणाऱ्या वर्णातील पहिला विसर्ग व दुसरा वर्ण व्यंजन किंवा स्वर असेल तर तेव्हा त्यास विसर्ग संधी असे म्हणतात.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;विसर्ग + व्यंजन किंवा विसर्ग + स्वर असे त्याचे स्वरूप असते. उदा. नि: + अंतर = निरंतर&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;उत्तर -&lt;/strong&gt;&amp;nbsp;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;महीश&lt;/strong&gt; हे&amp;nbsp;दीर्घत्व संधीचे उदाहरण आहे.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;महीश = मही + ईश (ई +&amp;nbsp;ई =&amp;nbsp;ई)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;वरील उदाहरणात&amp;nbsp;दोन सजातीय स्वर लागोपाठ आले आहेत म्हणून हे&amp;nbsp;दीर्घत्व स्वरसंधीचे उदाहरण होईल.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;दीर्घत्व संधी&lt;/strong&gt;&amp;nbsp;- दोन सजातीय स्वर लागोपाठ आल्यास या दोन्हींबद्दल त्याच जातीतील एकच दीर्घ स्वर येतो त्याला&amp;nbsp;दीर्घत्व संधी म्हणतात.&lt;/p&gt;

&lt;p&gt;दीर्घत्व संधीमध्ये संधी होऊन तयार झालेल्या वर्णाला काना, दुसरा उकार किंवा दुसरी वेलांटी असते.&lt;/p&gt;

&lt;p&gt;अ / आ +&amp;nbsp;अ / आ = आ (काना)&lt;/p&gt;

&lt;p&gt;इ / ई +&amp;nbsp;इ / ई =&amp;nbsp;ई (दुसरी वेलांटी)&lt;/p&gt;

&lt;p&gt;उ / ऊ + उ / ऊ = ऊ (दुसरा उकार)&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;इत्यादी&lt;/strong&gt; हे &lt;strong&gt;यणादेश&lt;/strong&gt; स्वरसंधीचे&amp;nbsp;उदाहरण आहे.&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;इत्यादी = इति + आदी = इ + आ =&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;य् + आ = या&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;सदैव&lt;/strong&gt; हे&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;&lt;strong&gt;वृद्धयादेश&lt;/strong&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;स्वरसंधीचे&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;उदाहरण आहे.&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;सदैव = सदा + एव &amp;nbsp;(आ + ए = ऐ)&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;उमेश&lt;/strong&gt; हे &lt;strong&gt;गुणादेश&lt;/strong&gt;&amp;nbsp;स्वरसंधीचे&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;उदाहरण आहे.&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;उमेश = उमा + ईश (आ + ई = ए)&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;संधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जोडशब्द तयार करताना पहिल्या शब्दातील शेवटचा वर्ण व दुसऱ्या शब्दातील पहिला वर्ण हे एकमेकांमध्ये मिसळतात व त्या दोन्हीबद्दल एक वर्ण तयार होतो. वर्णाच्या अशा एकत्र होण्याच्या प्रकाराला&amp;nbsp;संधी&amp;nbsp;असे म्हणतात.&lt;/p&gt;

&lt;p&gt;संधीचे&amp;nbsp;&lt;strong&gt;तीन&lt;/strong&gt;&amp;nbsp;प्रकार आहेत.&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;स्वरसंधी&lt;/li&gt;
	&lt;li&gt;व्यंजनसंधी&lt;/li&gt;
	&lt;li&gt;विसर्गसंधी&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;strong&gt;स्वरसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकमेकांच्या शेजारी येणारे वर्ण हे जर स्वरांनी जोडले असतील तर त्यांना स्वरसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;स्वर + स्वर असे याचे&amp;nbsp;स्वरूप असते.​&amp;nbsp;उदा. विद्या + अर्थी = विद्यार्थी&amp;nbsp; (आ + अ = आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;व्यंजनसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जवळ जवळ येणाऱ्या या दोन वर्णांपैकी दोन्ही वर्ण व्यंजने असतील किंवा पहिला वर्ण व्यंजन व दुसरा वर्ण स्वर असेल तर त्याला व्यंजनसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;व्यंजन&amp;nbsp;+&amp;nbsp;व्यंजन&amp;nbsp;किंवा स्वर&amp;nbsp;असे त्याचे स्वरूप असते.&amp;nbsp;&amp;nbsp;उदा. सत्&amp;nbsp;+ आचार = सदाचार (त्&amp;nbsp;+&amp;nbsp;आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;विसर्गसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकत्र येणाऱ्या वर्णातील पहिला विसर्ग व दुसरा वर्ण व्यंजन किंवा स्वर असेल तर तेव्हा त्यास विसर्ग संधी असे म्हणतात.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;विसर्ग + व्यंजन किंवा विसर्ग + स्वर असे त्याचे स्वरूप असते. उदा. नि: + अंतर = निरंतर&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;उत्तर -&lt;/strong&gt;&amp;nbsp;&lt;span style=&quot;&quot;&gt;क्षणैक&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;या शब्दाचा&lt;/span&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;विग्रह&lt;/span&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;क्षण + एक&lt;/strong&gt; असा होतो.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;क्षणैक हे &lt;strong&gt;वृद्धयादेश&lt;/strong&gt; स्वरसंधीचे उदाहरण आहे.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;क्षणैक =&amp;nbsp;क्षण + एक (अ + ए = ऐ)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;वृद्धयादेश&lt;/strong&gt; - &lt;strong&gt;अ/आ + ए/ऐ = ऐ&lt;/strong&gt; होतो व&amp;nbsp;&lt;strong&gt;अ/आ + ओ/औ&lt;/strong&gt; &lt;strong&gt;=&lt;/strong&gt; &lt;strong&gt;औ&lt;/strong&gt; होतो याला&amp;nbsp;वृद्धयादेश असे म्हणतात.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;संधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जोडशब्द तयार करताना पहिल्या शब्दातील शेवटचा वर्ण व दुसऱ्या शब्दातील पहिला वर्ण हे एकमेकांमध्ये मिसळतात व त्या दोन्हीबद्दल एक वर्ण तयार होतो. वर्णाच्या अशा एकत्र होण्याच्या प्रकाराला&amp;nbsp;संधी&amp;nbsp;असे म्हणतात.&lt;/p&gt;

&lt;p&gt;संधीचे&amp;nbsp;&lt;strong&gt;तीन&lt;/strong&gt;&amp;nbsp;प्रकार आहेत.&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;स्वरसंधी&lt;/li&gt;
	&lt;li&gt;व्यंजनसंधी&lt;/li&gt;
	&lt;li&gt;विसर्गसंधी&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;strong&gt;स्वरसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकमेकांच्या शेजारी येणारे वर्ण हे जर स्वरांनी जोडले असतील तर त्यांना स्वरसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;स्वर + स्वर असे याचे&amp;nbsp;स्वरूप असते.​&amp;nbsp;उदा. विद्या + अर्थी = विद्यार्थी&amp;nbsp; (आ + अ = आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;व्यंजनसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जवळ जवळ येणाऱ्या या दोन वर्णांपैकी दोन्ही वर्ण व्यंजने असतील किंवा पहिला वर्ण व्यंजन व दुसरा वर्ण स्वर असेल तर त्याला व्यंजनसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;व्यंजन&amp;nbsp;+&amp;nbsp;व्यंजन&amp;nbsp;किंवा स्वर&amp;nbsp;असे त्याचे स्वरूप असते.&amp;nbsp;&amp;nbsp;उदा. सत्&amp;nbsp;+ आचार = सदाचार (त्&amp;nbsp;+&amp;nbsp;आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;विसर्गसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकत्र येणाऱ्या वर्णातील पहिला विसर्ग व दुसरा वर्ण व्यंजन किंवा स्वर असेल तर तेव्हा त्यास विसर्ग संधी असे म्हणतात.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;विसर्ग + व्यंजन किंवा विसर्ग + स्वर असे त्याचे स्वरूप असते. उदा. नि: + अंतर = निरंतर&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;शब्द-&lt;/span&gt;&amp;nbsp;&amp;lsquo;अयोध्येश&amp;rsquo;&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;संधी विग्रह-&lt;/span&gt;&amp;nbsp;अयोध्या + ईश&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;स्वरसंधी&amp;nbsp;&lt;/span&gt;- जवळ येणारे वर्ण जर स्वर असतील, तर त्यास &amp;lsquo;स्वरसंधी&amp;#39; असे म्हणतात.&lt;br /&gt;
&lt;span style=&quot;font-weight: 700;&quot;&gt;उदा.&lt;/span&gt;&amp;nbsp;ग्रंथ + आलय = ग्रंथालय&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;नियम -&amp;nbsp;&lt;/span&gt;अ किंवा आ या स्वरापुढे इ किंवा ई आल्यास &amp;lsquo;ए&amp;rsquo; स्वर येतो व उ किंवा ऊ आल्यास &amp;lsquo;ओ&amp;rsquo; हा स्वर येतो. यालाच&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;गुणसंधी&amp;nbsp;&lt;/span&gt;असेही म्हणतात.&lt;br /&gt;
&lt;span style=&quot;font-weight: 700;&quot;&gt;उदा.&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ol style=&quot;&quot;&gt;
	&lt;li&gt;उमा + ईश [आ + ई = ए ] = उमेश&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;चंद्र + उदय [अ + उ = ओ ] = चंद्रोदय&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;महा + उत्सव [अ + उ&amp;nbsp;= ओ ] = महोत्सव&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;गण + ईश [अ + ई = ए ] = गणेश&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;ईश्वर + इच्छा [अ + इ = ए ] = ईश्वरेच्छा&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;महा + ऋषी [आ + ऋ = अर ] = महर्षी&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;देव + ऋषी [अ + ऋ = अर ] = देवर्षी&amp;nbsp;&lt;/li&gt;
&lt;/ol&gt;

&lt;p style=&quot;&quot;&gt;&amp;nbsp;&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;अशाप्रकारे&amp;nbsp;&amp;lsquo;अयोध्येश&amp;rsquo; या शब्दाचा&amp;nbsp;योग्य संधी विग्रह&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;अयोध्या + ईश&amp;#39;&amp;nbsp;&lt;/span&gt;असा होईल.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;उत्तर-&lt;u&gt;&amp;nbsp;&lt;span style=&quot;&quot;&gt;विसर्गसंधी&lt;/span&gt;&lt;/u&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;संधी&lt;/strong&gt;: जवळ जवळ आलेले दोन ध्वनी जोडण्याला संधी म्हणतात. संधी होत असतांना पहिल्या शब्दातील शेवटचा वर्ण आणि शेवटच्या शब्दातील पहिला वर्ण एकमेकात मिसळून त्या दोहोबद्दल एकच वर्ण तयार होतो याला संधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;संधीचे मुख्य तीन प्रकार आहेत:&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;स्वर संधी&lt;/li&gt;
	&lt;li&gt;विसर्ग संधी&lt;/li&gt;
	&lt;li&gt;व्यंजन संधी&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;विसर्ग&lt;/strong&gt; &lt;strong&gt;संधी&lt;/strong&gt;&lt;strong&gt;-&amp;nbsp;&lt;/strong&gt;एकत्र येणाऱ्या वर्णातील पहिला वर्ण विसर्ग व दुसरा वर्ण व्यंजन अथवा स्वर असेल तेव्हा त्यांना विसर्गसंधी म्हणतात.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;उदा-&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;निश्चिंत- नि: + चित&lt;/li&gt;
	&lt;li&gt;पुरस्कार- पुर: + कार&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(88, 89, 91);   &quot;&gt;मनोरंजन&amp;nbsp;&lt;/span&gt;- मन : +रंजन = मनोरंजन&amp;nbsp;&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(88, 89, 91);   &quot;&gt;वरील दिलेल्या प्रमाणे&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;box-sizing: border-box;   &quot;&gt;मनोरंजन हा शब्द&amp;nbsp;&lt;u style=&quot;box-sizing: border-box;&quot;&gt;&lt;em style=&quot;box-sizing: border-box;&quot;&gt;&lt;span style=&quot;box-sizing: border-box; font-weight: 700;&quot;&gt;&amp;nbsp;विसर्गसंधी&amp;nbsp;&lt;/span&gt;&lt;/em&gt;&lt;/u&gt;या संधीचा&amp;nbsp; प्रकार आहे.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;स्वर&lt;/strong&gt; &lt;strong&gt;संधी&lt;/strong&gt;&lt;strong&gt;:&amp;nbsp;&lt;/strong&gt;एकमेकांशेजारी येणारे वर्ण हे जर स्वरांनी जोडले असतील तर त्यांना &amp;lsquo;स्वरसंधी&amp;rsquo; असे म्हणतात किंवा एक पाठोपाठ एक येणारे दोन स्वर एकत्र होण्याच्या क्रियेला स्वरसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;उदा.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;धारोष्ण- धार + उष्ण&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;व्यंजनसंधी&lt;/strong&gt;&lt;strong&gt;-&amp;nbsp;&lt;/strong&gt;जवळ जवळ येणाऱ्या दोन वर्णांपैकी दोन्ही व्यंजने असतील किंवा पहिला वर्ण व्यंजन व दुसरा वर्ण स्वर असेल तेव्हा त्याला व्यंजन संधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;उदा-&amp;nbsp;&lt;/p&gt;

&lt;p&gt;विद्युल्लता-&amp;nbsp;विद्युत् + लता&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;उत्तर -&lt;/strong&gt;&amp;nbsp;&lt;span style=&quot;&quot;&gt;जगन्नाथ =&amp;nbsp;&lt;strong&gt;जगत् + नाथ&lt;/strong&gt;&amp;nbsp;&lt;/span&gt;ही योग्य&amp;nbsp;संधी आहे.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;जगन्नाथ हे &lt;strong&gt;अनुनासिक&lt;/strong&gt; संधीचे&amp;nbsp;&lt;/span&gt;उदाहरण आहे.&amp;nbsp;&lt;span style=&quot;&quot;&gt;अनुनासिक संधी हा व्यंजनसंधीचा उपप्रकार आहे.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;अनुनासिक संधी&lt;/strong&gt; - स्पर्श व्यंजन गटातील प्रथम व्यंजनापुढे&amp;nbsp;अनुनासिक आल्यास पहिल्या व्यंजनाबद्दल त्याच्याच वर्गातील&amp;nbsp;अनुनासिक येऊन संधी होते याला&amp;nbsp;अनुनासिक संधी म्हणतात.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;जगन्नाथ =&amp;nbsp;जगत् + नाथ&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;एकत्र येणारे वर्ण&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;&amp;nbsp;=&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;त्&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt; +&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;न् =&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;न्&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 14.98px;&quot;&gt;+&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 14.98px;&quot;&gt;न् =न्न&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;&lt;strong&gt;झालेला बदल &lt;/strong&gt;=&lt;/span&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;त् चा&amp;nbsp;न्&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;&lt;strong&gt;तयार झालेली संधी&lt;/strong&gt; =&lt;/span&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;जगन्नाथ&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;संधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जोडशब्द तयार करताना पहिल्या शब्दातील शेवटचा वर्ण व दुसऱ्या शब्दातील पहिला वर्ण हे एकमेकांमध्ये मिसळतात व त्या दोन्हीबद्दल एक वर्ण तयार होतो. वर्णाच्या अशा एकत्र होण्याच्या प्रकाराला&amp;nbsp;संधी&amp;nbsp;असे म्हणतात.&lt;/p&gt;

&lt;p&gt;संधीचे&amp;nbsp;&lt;strong&gt;तीन&lt;/strong&gt;&amp;nbsp;प्रकार आहेत.&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;स्वरसंधी&lt;/li&gt;
	&lt;li&gt;व्यंजनसंधी&lt;/li&gt;
	&lt;li&gt;विसर्गसंधी&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;strong&gt;स्वरसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकमेकांच्या शेजारी येणारे वर्ण हे जर स्वरांनी जोडले असतील तर त्यांना स्वरसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;उदा. विद्या + अर्थी = विद्यार्थी&amp;nbsp; (&amp;nbsp;आ + अ = आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;व्यंजनसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जवळ जवळ येणाऱ्या या दोन वर्णांपैकी दोन्ही वर्ण व्यंजने असतील किंवा पहिला वर्ण व्यंजन व दुसरा वर्ण स्वर असेल तर त्याला व्यंजनसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;व्यंजन&amp;nbsp;+&amp;nbsp;व्यंजन&amp;nbsp;किंवा स्वर&amp;nbsp;असे त्याचे स्वरूप असते.&amp;nbsp;&amp;nbsp;उदा. सत्&amp;nbsp;+ आचार = सदाचार (त्&amp;nbsp;+&amp;nbsp;आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;विसर्गसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकत्र येणाऱ्या वर्णातील पहिला विसर्ग व दुसरा वर्ण व्यंजन किंवा स्वर असेल तर तेव्हा त्यास विसर्ग संधी असे म्हणतात.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;विसर्ग + व्यंजन किंवा विसर्ग + स्वर असे त्याचे स्वरूप असते. उदा. नि: + अंतर = निरंतर&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;उत्तर -&lt;/strong&gt;&amp;nbsp;&lt;span style=&quot;&quot;&gt;गायन&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;या शब्दाचा&lt;/span&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;विग्रह&lt;/span&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;गै + अन&lt;/strong&gt;&amp;nbsp;&lt;/span&gt;असा होतो.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;गायन हे &lt;strong&gt;अयादी आदेश&lt;/strong&gt; स्वरसंधीचे उदाहरण आहे.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;गायन =&amp;nbsp;गै + अन = ऐ + अ = आ&lt;/span&gt;&lt;span lang=&quot;AR-SA&quot; style=&quot; line-height: 107%; &quot;&gt;य् + अ = आय&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;अयादी आदेश&lt;/strong&gt; - ए, ऐ, ओ, औ या स्वरांपुढे जर एखादा स्वर आला तर त्याबद्दल अनुक्रमे अय्, आय्, अ&lt;/span&gt;&lt;span lang=&quot;AR-SA&quot; style=&quot; line-height: 107%; &quot;&gt;व्, आव् असे आदेश होऊन पुढील स्वर यात मिसळतो याला अयादी आदेश म्हणतात. उदा. नयन = ने + अन = ए + अ = अ&lt;/span&gt;&lt;span style=&quot;&quot;&gt;य् + अ =अय&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;संधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जोडशब्द तयार करताना पहिल्या शब्दातील शेवटचा वर्ण व दुसऱ्या शब्दातील पहिला वर्ण हे एकमेकांमध्ये मिसळतात व त्या दोन्हीबद्दल एक वर्ण तयार होतो. वर्णाच्या अशा एकत्र होण्याच्या प्रकाराला&amp;nbsp;संधी&amp;nbsp;असे म्हणतात.&lt;/p&gt;

&lt;p&gt;संधीचे&amp;nbsp;&lt;strong&gt;तीन&lt;/strong&gt;&amp;nbsp;प्रकार आहेत.&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;स्वरसंधी&lt;/li&gt;
	&lt;li&gt;व्यंजनसंधी&lt;/li&gt;
	&lt;li&gt;विसर्गसंधी&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;strong&gt;स्वरसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकमेकांच्या शेजारी येणारे वर्ण हे जर स्वरांनी जोडले असतील तर त्यांना स्वरसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;स्वर + स्वर असे याचे&amp;nbsp;स्वरूप असते.​&amp;nbsp;उदा. विद्या + अर्थी = विद्यार्थी&amp;nbsp; (आ + अ = आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;व्यंजनसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जवळ जवळ येणाऱ्या या दोन वर्णांपैकी दोन्ही वर्ण व्यंजने असतील किंवा पहिला वर्ण व्यंजन व दुसरा वर्ण स्वर असेल तर त्याला व्यंजनसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;व्यंजन&amp;nbsp;+&amp;nbsp;व्यंजन&amp;nbsp;किंवा स्वर&amp;nbsp;असे त्याचे स्वरूप असते.&amp;nbsp;&amp;nbsp;उदा. सत्&amp;nbsp;+ आचार = सदाचार (त्&amp;nbsp;+&amp;nbsp;आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;विसर्गसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकत्र येणाऱ्या वर्णातील पहिला विसर्ग व दुसरा वर्ण व्यंजन किंवा स्वर असेल तर तेव्हा त्यास विसर्ग संधी असे म्हणतात.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;विसर्ग + व्यंजन किंवा विसर्ग + स्वर असे त्याचे स्वरूप असते. उदा. नि: + अंतर = निरंतर&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;उत्तर -&lt;/strong&gt;&amp;nbsp;&lt;span style=&quot;&quot;&gt;महा + ईश =&amp;nbsp;&lt;strong&gt;महेश&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;महेश&amp;nbsp;&lt;/span&gt;&lt;strong&gt;गुणादेश&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;स्वरसंधीचे&lt;/strong&gt;&amp;nbsp;उदाहरण आहे.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;महेश =&amp;nbsp;महा + ईश (आ + ई = ए)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;गुणादेश स्वरसंधी&lt;/strong&gt; -&amp;nbsp;अ /आ + इ /&amp;nbsp;ई = ए,&amp;nbsp;अ /आ + उ / ऊ = ओ,&amp;nbsp;अ /आ + ऋ = अर&amp;nbsp; याप्रमाणे दोन वर्ण एकत्र येऊन&amp;nbsp;ए,&amp;nbsp;ओ,&amp;nbsp;अर असे बदल झाल्यास त्याला गुणादेश स्वरसंधी म्हणतात.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;संधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जोडशब्द तयार करताना पहिल्या शब्दातील शेवटचा वर्ण व दुसऱ्या शब्दातील पहिला वर्ण हे एकमेकांमध्ये मिसळतात व त्या दोन्हीबद्दल एक वर्ण तयार होतो. वर्णाच्या अशा एकत्र होण्याच्या प्रकाराला&amp;nbsp;संधी&amp;nbsp;असे म्हणतात.&lt;/p&gt;

&lt;p&gt;संधीचे&amp;nbsp;&lt;strong&gt;तीन&lt;/strong&gt;&amp;nbsp;प्रकार आहेत.&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;स्वरसंधी&lt;/li&gt;
	&lt;li&gt;व्यंजनसंधी&lt;/li&gt;
	&lt;li&gt;विसर्गसंधी&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;strong&gt;स्वरसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकमेकांच्या शेजारी येणारे वर्ण हे जर स्वरांनी जोडले असतील तर त्यांना स्वरसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;स्वर + स्वर असे याचे&amp;nbsp;स्वरूप असते.​&amp;nbsp;उदा. विद्या + अर्थी = विद्यार्थी&amp;nbsp; (आ + अ = आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;व्यंजनसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जवळ जवळ येणाऱ्या या दोन वर्णांपैकी दोन्ही वर्ण व्यंजने असतील किंवा पहिला वर्ण व्यंजन व दुसरा वर्ण स्वर असेल तर त्याला व्यंजनसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;व्यंजन&amp;nbsp;+&amp;nbsp;व्यंजन&amp;nbsp;किंवा स्वर&amp;nbsp;असे त्याचे स्वरूप असते.&amp;nbsp;&amp;nbsp;उदा. सत्&amp;nbsp;+ आचार = सदाचार (त्&amp;nbsp;+&amp;nbsp;आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;विसर्गसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकत्र येणाऱ्या वर्णातील पहिला विसर्ग व दुसरा वर्ण व्यंजन किंवा स्वर असेल तर तेव्हा त्यास विसर्ग संधी असे म्हणतात.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;विसर्ग + व्यंजन किंवा विसर्ग + स्वर असे त्याचे स्वरूप असते. उदा. नि: + अंतर = निरंतर&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;शब्द:&amp;nbsp;&lt;/strong&gt; सूर्यास्त&lt;br /&gt;
&lt;strong&gt;संधी विग्रह&lt;/strong&gt;: सूर्य + अस्त&lt;br /&gt;
&lt;strong&gt;संधी प्रकार:&lt;/strong&gt; सवर्णदीर्घ संधी&lt;/p&gt;

&lt;p&gt;&lt;br /&gt;
&lt;strong&gt;सवर्णदीर्घ संधी: &lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;वरील शब्दात पाहिल्याशाब्दाचा शेवटचा वर्ण ऱ्हस्व स्वर किंवा दीर्घ स्वर असून दुसऱ्या शब्दातील पहिला वर्ण ऱ्हस्व स्वर किंवा दीर्घ स्वर आहे. या दोहोंबद्दल तयार झालेला स्वर हा त्याच प्रकारातील &lt;strong&gt;दीर्घ स्वर &lt;/strong&gt;आहे.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;नियम-&lt;/strong&gt; ऱ्हस्व स्वरापुढे किंवा दीर्घ स्वरापुढे तोच स्वर ऱ्हस्व किंवा दीर्घ आल्यास म्हणजेच दोन सजातीय स्वर लागोपाठ आल्यास त्या दोहोंबद्दल त्याच जातीतील एकच दीर्घ स्वर येतो. यालाच सवर्णदीर्घ संधी असे म्हणतात.&lt;br /&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;उत्तर -&lt;/strong&gt;&amp;nbsp;&lt;span style=&quot;&quot;&gt;फल + आहार =&amp;nbsp;&lt;strong&gt;फलाहार&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;फलाहार हे &lt;strong&gt;दीर्घत्व&lt;/strong&gt; स्वरसंधीचे उदाहरण आहे.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;फलाहार =&amp;nbsp;फल + आहार (अ + आ = आ)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;वरील उदाहरणात&amp;nbsp;दोन सजातीय स्वर लागोपाठ आले आहेत म्हणून हे&amp;nbsp;दीर्घत्व स्वरसंधीचे उदाहरण होईल.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;दीर्घत्व संधी&lt;/strong&gt; - दोन सजातीय स्वर लागोपाठ आल्यास या दोन्हींबद्दल त्याच जातीतील एकच दीर्घ स्वर येतो त्याला&amp;nbsp;दीर्घत्व संधी म्हणतात.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;दीर्घत्व संधीमध्ये संधी होऊन तयार झालेल्या वर्णाला काना, दुसरा उकार किंवा दुसरी वेलांटी असते.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;अ / आ +&amp;nbsp;अ / आ = आ (काना)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;इ / ई +&amp;nbsp;इ / ई =&amp;nbsp;ई (दुसरी वेलांटी)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;उ / ऊ + उ / ऊ = ऊ (दुसरा उकार)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;संधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जोडशब्द तयार करताना पहिल्या शब्दातील शेवटचा वर्ण व दुसऱ्या शब्दातील पहिला वर्ण हे एकमेकांमध्ये मिसळतात व त्या दोन्हीबद्दल एक वर्ण तयार होतो. वर्णाच्या अशा एकत्र होण्याच्या प्रकाराला&amp;nbsp;संधी&amp;nbsp;असे म्हणतात.&lt;/p&gt;

&lt;p&gt;संधीचे&amp;nbsp;&lt;strong&gt;तीन&lt;/strong&gt;&amp;nbsp;प्रकार आहेत.&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;स्वरसंधी&lt;/li&gt;
	&lt;li&gt;व्यंजनसंधी&lt;/li&gt;
	&lt;li&gt;विसर्गसंधी&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;strong&gt;स्वरसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकमेकांच्या शेजारी येणारे वर्ण हे जर स्वरांनी जोडले असतील तर त्यांना स्वरसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;स्वर + स्वर असे याचे&amp;nbsp;स्वरूप असते.​&amp;nbsp;उदा. विद्या + अर्थी = विद्यार्थी&amp;nbsp; (आ + अ = आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;व्यंजनसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जवळ जवळ येणाऱ्या या दोन वर्णांपैकी दोन्ही वर्ण व्यंजने असतील किंवा पहिला वर्ण व्यंजन व दुसरा वर्ण स्वर असेल तर त्याला व्यंजनसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;व्यंजन&amp;nbsp;+&amp;nbsp;व्यंजन&amp;nbsp;किंवा स्वर&amp;nbsp;असे त्याचे स्वरूप असते.&amp;nbsp;&amp;nbsp;उदा. सत्&amp;nbsp;+ आचार = सदाचार (त्&amp;nbsp;+&amp;nbsp;आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;विसर्गसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकत्र येणाऱ्या वर्णातील पहिला विसर्ग व दुसरा वर्ण व्यंजन किंवा स्वर असेल तर तेव्हा त्यास विसर्ग संधी असे म्हणतात.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;विसर्ग + व्यंजन किंवा विसर्ग + स्वर असे त्याचे स्वरूप असते. उदा. नि: + अंतर = निरंतर&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;संधी-&lt;/strong&gt;&amp;nbsp;गुरूपदेश&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;संधी विग्रह&lt;/strong&gt;- गुरू + उपदेश&lt;br /&gt;
&lt;strong&gt;संधी प्रकार&lt;/strong&gt;- सवर्णदीर्घ संधी&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;स्वरसंधी -&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;जवळ येणारे वर्ण जर स्वर असतील, तर त्यास &amp;lsquo;स्वरसंधी&amp;#39; असे म्हणतात.&lt;/span&gt;&lt;br style=&quot;&quot; /&gt;
&lt;span style=&quot;font-weight: 700; &quot;&gt;उदा&lt;/span&gt;&lt;span style=&quot;&quot;&gt;. ग्रंथ + आलय = ग्रंथालय&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;सवर्णदीर्घ संधी:&amp;nbsp;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;वरील शब्दात पहिल्या शब्दाचा शेवटचा वर्ण ऱ्हस्व स्वर किंवा दीर्घ स्वर असून दुसऱ्या शब्दातील पहिला वर्ण ऱ्हस्व स्वर किंवा दीर्घ स्वर आहे. या दोहोंबद्दल तयार झालेला स्वर हा त्याच प्रकारातील दीर्घ स्वर आहे.&lt;br /&gt;
&lt;strong&gt;नियम- &lt;/strong&gt;ऱ्हस्व स्वरापुढे किंवा दीर्घ स्वरापुढे तोच स्वर ऱ्हस्व किंवा दीर्घ आल्यास म्हणजेच दोन सजातीय स्वर लागोपाठ आल्यास त्या दोहोंबद्दल त्याच जातीतील एकच दीर्घ स्वर येतो. यालाच सवर्णदीर्घ संधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;अशाप्रकारे &lt;strong&gt;&lt;span style=&quot;&quot;&gt;गुरू + उपदेश&lt;/span&gt;&lt;/strong&gt; याची संधी &lt;strong&gt;&lt;span style=&quot;&quot;&gt;गुरूपदेश&lt;/span&gt;&lt;/strong&gt; अशी होईल आणि प्रस्तुत पर्यायांपैकी&amp;nbsp;केवळ हीच &lt;strong&gt;स्वर संधी &lt;/strong&gt;आहे.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;अन्य पर्यायांचे स्पष्टीकरण-&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;सदाचार या शब्दाचा संधी विग्रह&amp;nbsp;&lt;/span&gt;सत् + आचार&amp;nbsp;असा होईल आणि म्हणून ही व्यंजन संधी आहे.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;वाक्पती या शब्दाचा संधी विग्रह वाग् + पती असा होईल आणि म्हणून ही देखील व्यंजन संधी आहे.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;सन्मती या शब्दाचा संधी विग्रह सत् + मती असा होईल आणि म्हणून ही व्यंजन संधी आहे.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;अधोवदन या शब्दाचा संधी विग्रह अध: + वदन असा होईल आणि म्हणून ही विसर्ग संधी आहे.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;उत्तर-&amp;nbsp;&lt;span style=&quot;&quot;&gt;उत् + शिष्ट&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;संधी-&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;संधी होत असतांना पहिल्या शब्दातील शेवटचा वर्ण आणि शेवटच्या शब्दातील पहिला वर्ण एकमेकात मिसळून त्या दोहोबद्दल एकच वर्ण तयार होतो याला संधी असे म्हणतात.&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;संधी म्हणजे सांधणे, जोडणे&amp;nbsp;किंवा एकत्र करणे होय.&lt;/li&gt;
	&lt;li&gt;जवळ जवळ आलेले दोन ध्वनी जोडण्याला संधी म्हणतात.&lt;/li&gt;
	&lt;li&gt;संधी हा प्रकार संस्कृत मधून मराठीत आला आहे.&lt;/li&gt;
	&lt;li&gt;संधी म्हणजे वर्णांचे एकत्रीकरण होय.&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;संधीचे मुख्य तीन प्रकार आहेत.&lt;br /&gt;
1) स्वरसंधी&lt;br /&gt;
2) व्यंजन संधी&lt;br /&gt;
3) विसर्गसंधी&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;व्यंजन संधी :&lt;/strong&gt;&lt;br /&gt;
दोन व्यंजने किंवा यापैकी दूसरा वर्ण स्वर असेल तर त्याला मिळून तयार होणार्&amp;zwj;या संधीला व्यंजन संधी असे म्हणतात.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;व्यंजन संधीचे प्रकार :&lt;/strong&gt;&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;प्रथम व्यंजन संधी : (व्यंजन + व्यंजन)&lt;/li&gt;
	&lt;li&gt;तृतीय व्यंजन संधी : (व्यंजन + व्यंजन / स्वर)&lt;/li&gt;
	&lt;li&gt;अनुनासिक व्यंजन संधी : (व्यंजन + व्यंजन)&lt;/li&gt;
	&lt;li&gt;&amp;lsquo;त&amp;rsquo; ची व्यंजन संधी : (व्यंजन + व्यंजन / स्वर)&lt;/li&gt;
	&lt;li&gt;&amp;lsquo;म&amp;rsquo; ची व्यंजन संधी : (व्यंजन + व्यंजन / स्वर)&lt;/li&gt;
	&lt;li&gt;&amp;lsquo;छ&amp;rsquo; ची व्यंजन संधी : (स्वर + व्यंजन)&lt;/li&gt;
	&lt;li&gt;&amp;lsquo;न&amp;rsquo; ची व्यंजन संधी : (व्यंजन + व्यंजन / स्वर)&lt;/li&gt;
	&lt;li&gt;&amp;lsquo;र&amp;rsquo; ची व्यंजन संधी : (व्यंजन + व्यंजन)&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;&amp;lsquo;त&amp;rsquo; ची व्यंजन संधी :-&amp;nbsp;&lt;/strong&gt;&lt;br /&gt;
अ) त् + च = च + च = च्च&amp;nbsp;&lt;br /&gt;
&amp;nbsp; &amp;nbsp;त् + छ = च + छ = च्छ&amp;nbsp;&amp;nbsp;&lt;br /&gt;
&lt;strong&gt;उदा.&lt;/strong&gt;&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;उत् + चारण = उच्चारण&lt;/li&gt;
	&lt;li&gt;सत् + चरित्र = सच्चरित्र&amp;nbsp;&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;उत् + छेद = उच्छेद&amp;nbsp;&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;अशाचप्रकारे&amp;nbsp;&lt;span style=&quot;&quot;&gt;&amp;lsquo;उच्छिष्ट&amp;rsquo; या शब्दाची संधी&lt;strong&gt; &amp;#39;उत् + शिष्ट&amp;#39;&lt;/strong&gt; अशी होईल.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;संधीयुक्त शब्द-&lt;/strong&gt;&amp;nbsp;&lt;span style=&quot;&quot;&gt;​​अभीष्ट&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;संधी विग्रह-&lt;/strong&gt;&amp;nbsp;अभि + इष्ट&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;संधी प्रकार-&lt;/strong&gt; सवर्णदीर्घ संधी (स्वरसंधी)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;स्वरसंधी -&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;जवळ येणारे वर्ण जर स्वर असतील, तर त्यास &amp;lsquo;स्वरसंधी&amp;#39; असे म्हणतात.&lt;/span&gt;&lt;br style=&quot;&quot; /&gt;
&lt;span style=&quot;font-weight: 700; &quot;&gt;उदा&lt;/span&gt;&lt;span style=&quot;&quot;&gt;. ग्रंथ + आलय = ग्रंथालय&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;नियम-&lt;/strong&gt;&amp;nbsp;दोन सजातीय स्वर एकमेकांशेजारी आले असता त्या दोहोंबद्दल त्याच जातीतील एकच दीर्घ स्वर येतो.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;उदा-&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;मुनि + इच्छा= इ+इ= ई= मुनीच्छा&lt;/li&gt;
	&lt;li&gt;मुख्य + आलय=&amp;nbsp;अ + आ= आ= मुख्यालय&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;अभि + इष्ट=&amp;nbsp;इ+इ= ई=&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;&quot;&gt;​&lt;strong&gt;अभीष्ट&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;अशाच प्रकारे&amp;nbsp;&lt;span style=&quot;&quot;&gt;​अभीष्ट याची फोड&amp;nbsp;&lt;strong&gt;अभि + इष्ट &lt;/strong&gt;अशी होईल.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;उत्तर-&amp;nbsp;दिग + अंबर = दिगंबर&lt;/strong&gt; हा चुकीचा पर्याय आहे.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;दि&lt;/span&gt;&lt;/strong&gt;&lt;span lang=&quot;AR-SA&quot; style=&quot; line-height: 107%; &quot;&gt;&lt;strong&gt;क्&lt;/strong&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;+ अंबर = दिगंबर&lt;/strong&gt; हे बरोबर होईल.&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;वरील प्रश्नात&amp;nbsp;अजादी,&amp;nbsp;सद्भावना आणि दिगंबर ही &lt;strong&gt;तृतीय व्यंजनसंधीची&lt;/strong&gt; उदाहरणे आहेत.&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;तृतीय व्यंजन संधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;दोन शब्दाची संधी होत असतांना पहिल्या शब्दातील शेवटचा वर्ण क,&amp;nbsp;च,&amp;nbsp;ट,&amp;nbsp;त,&amp;nbsp;प यापैकी कोणताही वर्ण आल्यास त्यापासून संधी होत असतांना त्या वर्णाच्या&amp;nbsp;जागी त्याच वर्गातील तृतीय व्यंजन येते या संधीला&amp;nbsp;तृतीय व्यंजन संधी&amp;nbsp;असे म्हणतात.&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;दिगंबर&lt;/strong&gt; =&amp;nbsp;दि&lt;/span&gt;&lt;span lang=&quot;AR-SA&quot; style=&quot; line-height: 14.98px;&quot;&gt;क्&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;+ अंबर&amp;nbsp;&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;एकत्र येणारे वर्ण&amp;nbsp;&lt;/span&gt;=&amp;nbsp;&lt;span style=&quot;&quot;&gt;क् + अ =&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;AR-SA&quot; style=&quot; line-height: 14.98px;&quot;&gt;ग्&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;+ अ = ग&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;झालेला बदल =&lt;/span&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;क् चा&amp;nbsp;ग्&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;तयार झालेली संधी =&lt;/span&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;दिगंबर&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;अजादी&lt;/strong&gt; =&amp;nbsp;अच् + आदी&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 14.98px;&quot;&gt;एकत्र येणारे वर्ण&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;=&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;HI&quot; style=&quot; line-height: 107%; &quot;&gt;च्&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;+ आ =&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;AR-SA&quot; style=&quot; line-height: 107%; &quot;&gt;ज्&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;+ आ = जा&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 14.98px;&quot;&gt;झालेला बदल =&lt;/span&gt;&lt;span style=&quot; line-height: 14.98px;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;च् चा&amp;nbsp;ज्&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;तयार झालेली संधी =&amp;nbsp;अजादी&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;सद्भावना&lt;/strong&gt; =&amp;nbsp;सत् + भावना&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 14.98px;&quot;&gt;एकत्र येणारे वर्ण&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;=&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;त् +&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;AR-SA&quot; style=&quot; line-height: 107%; &quot;&gt;भ्&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;=&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;AR-SA&quot; style=&quot; line-height: 107%; &quot;&gt;द्&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 14.98px;&quot;&gt;+&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;AR-SA&quot; style=&quot; line-height: 14.98px;&quot;&gt;भ् =&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;दभ्&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;झालेला बदल =&amp;nbsp;त् चा&amp;nbsp;द्&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;तयार झालेली संधी =&amp;nbsp;सद्भावना&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;संधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जोडशब्द तयार करताना पहिल्या शब्दातील शेवटचा वर्ण व दुसऱ्या शब्दातील पहिला वर्ण हे एकमेकांमध्ये मिसळतात व त्या दोन्हीबद्दल एक वर्ण तयार होतो. वर्णाच्या अशा एकत्र होण्याच्या प्रकाराला&amp;nbsp;संधी&amp;nbsp;असे म्हणतात.&lt;/p&gt;

&lt;p&gt;संधीचे&amp;nbsp;&lt;strong&gt;तीन&lt;/strong&gt;&amp;nbsp;प्रकार आहेत.&lt;/p&gt;

&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp;1.&amp;nbsp;स्वरसंधी&lt;/p&gt;

&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp;2.&amp;nbsp;व्यंजनसंधी&lt;/p&gt;

&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp;3.&amp;nbsp;विसर्गसंधी&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;स्वरसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकमेकांच्या शेजारी येणारे वर्ण हे जर स्वरांनी जोडले असतील तर त्यांना स्वरसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;उदा. विद्या + अर्थी = विद्यार्थी&amp;nbsp; (&amp;nbsp;आ + अ = आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;व्यंजनसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जवळ जवळ येणाऱ्या या दोन वर्णांपैकी दोन्ही वर्ण व्यंजने असतील किंवा पहिला वर्ण व्यंजन व दुसरा वर्ण स्वर असेल तर त्याला व्यंजनसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;व्यंजन&amp;nbsp;+&amp;nbsp;व्यंजन&amp;nbsp;किंवा स्वर&amp;nbsp;असे त्याचे स्वरूप असते.&amp;nbsp;&amp;nbsp;उदा. स&lt;span style=&quot;&quot;&gt;त्&lt;/span&gt; + आचार = सदाचार (&lt;span style=&quot;&quot;&gt;त्&amp;nbsp;&lt;/span&gt;+ आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;विसर्गसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकत्र येणाऱ्या वर्णातील पहिला विसर्ग व दुसरा वर्ण व्यंजन किंवा स्वर असेल तर तेव्हा त्यास विसर्ग संधी असे म्हणतात.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;विसर्ग + व्यंजन किंवा विसर्ग + स्वर असे त्याचे स्वरूप असते. उदा. नि: + अंतर = निरंतर&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;उत्तर -&lt;/strong&gt;&amp;nbsp;&lt;span style=&quot;&quot;&gt;पित्राज्ञा =&amp;nbsp;&lt;strong&gt;पितृ + आज्ञा&lt;/strong&gt;&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;ही योग्य&lt;/span&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;संधी आहे.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;पित्राज्ञा हे &lt;strong&gt;यणादेश&lt;/strong&gt;&amp;nbsp;&lt;/span&gt;&lt;strong&gt;स्वरसंधीचे&lt;/strong&gt;&amp;nbsp;उदाहरण आहे.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;पित्राज्ञा =&amp;nbsp;पितृ + आज्ञा = ऋ + आ =&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;AR-SA&quot; style=&quot; line-height: 107%; &quot;&gt;र् + आ = रा&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span lang=&quot;AR-SA&quot; style=&quot; line-height: 107%; &quot;&gt;इ, उ, ऋ (ह्रस्व किंवा दीर्घ) यांच्या पुढे विजातीय स्वर आल्यास इ/ई बद्दल&amp;nbsp;&lt;strong&gt;य्&lt;/strong&gt;, उ/ऊ&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;बद्दल&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;AR-SA&quot; style=&quot; line-height: 107%; &quot;&gt;&lt;strong&gt;व्&lt;/strong&gt; तर&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;ऋ&amp;nbsp;बद्दल&amp;nbsp;&lt;strong&gt;र् &lt;/strong&gt;वर्ण येतात आणि त्यात पुढील स्वर मिसळून संधी तयार होते. अशाप्रकारे&amp;nbsp;य्,&amp;nbsp;व्,&amp;nbsp;र् असे बदल होतात त्याला &lt;strong&gt;यणादेश&lt;/strong&gt; असे म्हणतात.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;संधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जोडशब्द तयार करताना पहिल्या शब्दातील शेवटचा वर्ण व दुसऱ्या शब्दातील पहिला वर्ण हे एकमेकांमध्ये मिसळतात व त्या दोन्हीबद्दल एक वर्ण तयार होतो. वर्णाच्या अशा एकत्र होण्याच्या प्रकाराला&amp;nbsp;संधी&amp;nbsp;असे म्हणतात.&lt;/p&gt;

&lt;p&gt;संधीचे&amp;nbsp;&lt;strong&gt;तीन&lt;/strong&gt;&amp;nbsp;प्रकार आहेत.&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;स्वरसंधी&lt;/li&gt;
	&lt;li&gt;व्यंजनसंधी&lt;/li&gt;
	&lt;li&gt;विसर्गसंधी&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;strong&gt;स्वरसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकमेकांच्या शेजारी येणारे वर्ण हे जर स्वरांनी जोडले असतील तर त्यांना स्वरसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;उदा. विद्या + अर्थी = विद्यार्थी&amp;nbsp; (&amp;nbsp;आ + अ = आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;व्यंजनसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जवळ जवळ येणाऱ्या या दोन वर्णांपैकी दोन्ही वर्ण व्यंजने असतील किंवा पहिला वर्ण व्यंजन व दुसरा वर्ण स्वर असेल तर त्याला व्यंजनसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;व्यंजन&amp;nbsp;+&amp;nbsp;व्यंजन&amp;nbsp;किंवा स्वर&amp;nbsp;असे त्याचे स्वरूप असते.&amp;nbsp;&amp;nbsp;उदा. सत्&amp;nbsp;+ आचार = सदाचार (त्&amp;nbsp;+&amp;nbsp;आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;विसर्गसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकत्र येणाऱ्या वर्णातील पहिला विसर्ग व दुसरा वर्ण व्यंजन किंवा स्वर असेल तर तेव्हा त्यास विसर्ग संधी असे म्हणतात.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;विसर्ग + व्यंजन किंवा विसर्ग + स्वर असे त्याचे स्वरूप असते. उदा. नि: + अंतर = निरंतर&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;उत्तर-&amp;nbsp;&lt;u&gt;लोक आपली स्तुती करोत किंवा लोक आपली निंदा करोत&lt;/u&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;खालील&amp;nbsp;तीन&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;प्रकार&lt;/strong&gt; &lt;strong&gt;हे&lt;/strong&gt; &lt;strong&gt;वाक्यात&lt;/strong&gt; &lt;strong&gt;असणाऱ्या&lt;/strong&gt; &lt;strong&gt;विधानांच्या&lt;/strong&gt; &lt;strong&gt;संख्येवरून&lt;/strong&gt; &lt;strong&gt;पडले&lt;/strong&gt; &lt;strong&gt;आहेत.&lt;/strong&gt;&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;केवळ वाक्य&lt;/li&gt;
	&lt;li&gt;संयुक्त वाक्य&lt;/li&gt;
	&lt;li&gt;मिश्र वाक्य&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;संयुक्त&lt;/strong&gt; &lt;strong&gt;वाक्य&lt;/strong&gt;&lt;strong&gt; -&amp;nbsp;&lt;/strong&gt;जेव्हा दोन किंवा अधिक वाक्ये उभयान्वयी अव्ययांनी जोडली जातात त्यास संयुक्त वाक्य असे म्हणतात.&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;समुच्चबोधक -आणि ,व, शिवाय&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;विकल्पबोधक -अथवा ,किंवा ,कि&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;न्यूनत्वबोधक -पण ,परंतु ,परी&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;परिणामबोधक -म्हणून ,सबब&amp;nbsp;&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;strong&gt;उदा. &lt;/strong&gt;देह जावो अथवा राहो,पाऊस आला आणि मोर नाचू लागला.&lt;/p&gt;

&lt;p&gt;वरील दिलेल्याप्रमाणें&amp;nbsp;&lt;span style=&quot;color: rgb(88, 89, 91);   &quot;&gt;&lt;u&gt;&lt;em&gt;&lt;strong&gt;लोक आपली स्तुती करोत किंवा लोक आपली निंदा करोत&lt;/strong&gt;&lt;/em&gt;&lt;/u&gt; हे संयुक्त वाक्य आहे.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;उत्तर&lt;/strong&gt;-&amp;nbsp;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;केवल वाक्य&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;वाक्यांचे मुख्य ३ प्रकार पडतात-&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;केवल वाक्य&lt;/li&gt;
	&lt;li&gt;संयुक्त वाक्य&lt;/li&gt;
	&lt;li&gt;मिश्र वाक्य&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;केवल वाक्य :- &lt;/strong&gt;ज्या वाक्यात एकच उद्देश आणि एकच विधेय असते, त्या वाक्यास केवल वाक्य किंवा शुद्ध वाक्य म्हणतात.&lt;/p&gt;

&lt;p&gt;या वाक्यात एकच मुख्य क्रिया असते. ज्या वेळेला अनेक वाक्यापासून एकच केवल वाक्य तयार करायचे असल्यास शेवटची क्रियापद कायम ठेवून पहिल्या क्रियापदांना ऊन,हून,करिता,साठी, असतात इ यांसारखे प्रत्यय जोडून एकच शेवटची मुख्य क्रिया कायम ठेवल्यास केवल वाक्य तयार होते.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;उदा :- &lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;1) सूर्य रोज पूर्वेला उगावतो.&lt;/p&gt;

&lt;p&gt;2) मीरा पुस्तक वाचते. याप्रमाणेच,&lt;/p&gt;

&lt;p&gt;3)&amp;nbsp; &lt;strong&gt;आत्ता तुम्ही घरात या.&amp;nbsp;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;तु फार चतुर आहेस हे &lt;strong&gt;विधानार्थी&lt;/strong&gt; वाक्य आहे.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;विधांनार्थी वाक्य&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;ज्या वाक्यात कर्त्यांने केवळ विधान केलेले असते&amp;nbsp;त्या वाक्याला&amp;nbsp;विधानार्थी वाक्य&amp;nbsp;असे म्हणतात. उदा. मी बारावीत शिकत आहे.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;आज्ञार्थी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;ज्या क्रियापदाच्या रुपावरुन आज्ञा,&amp;nbsp;मागणी,&amp;nbsp;आशीर्वाद,&amp;nbsp;सल्ला,&amp;nbsp;विनंती,&amp;nbsp;प्रार्थना किंवा उपदेश याचा बोध होत असेल तर त्याला&amp;nbsp;आज्ञार्थी&amp;nbsp;क्रियापद असे म्हणतात. उदा. मला तुमचे पेन द्या.&lt;o:p&gt;&lt;/o:p&gt;&lt;/p&gt;

&lt;p&gt;मराठीत वाक्याचे&amp;nbsp;&lt;strong&gt;दोन&lt;/strong&gt;&amp;nbsp;प्रकारात वर्गीकरण केले जाते.&lt;o:p&gt;&lt;/o:p&gt;&lt;/p&gt;

&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp;1. अर्थावरून पडणारे प्रकार&lt;o:p&gt;&lt;/o:p&gt;&lt;/p&gt;

&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp;2. वाक्यात असणार्&amp;zwj;या विधानांच्या संख्येवरून पडणारे प्रकार&lt;o:p&gt;&lt;/o:p&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;अर्थावरून पडणारे प्रकार -&lt;/strong&gt;&amp;nbsp;&lt;o:p&gt;&lt;/o:p&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;विधांनार्थी वाक्य&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;ज्या वाक्यात कर्त्यांने केवळ विधान केलेले असते. त्या वाक्याला&amp;nbsp;विधानार्थी वाक्य&amp;nbsp;असे म्हणतात. उदा. मी गावाला जात आहे.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;प्रश्नार्थी वाक्य&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;ज्या वाक्यात कर्त्यांने प्रश्न विचारलेला असतो त्या वाक्याला&amp;nbsp;प्रश्नार्थी वाक्य&amp;nbsp;असे म्हणतात.&amp;nbsp;उदा. तू कधी येणार?&lt;o:p&gt;&lt;/o:p&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;उद्गारार्थी वाक्य -&lt;/strong&gt;&amp;nbsp;ज्या वाक्यामध्ये कर्त्याने आपल्या मनात निर्माण झालेल्या भावनेचा उद्गार काढलेला असतो. त्या वाक्याला&amp;nbsp;उद्गारार्थी वाक्य&amp;nbsp;असे म्हणतात. उदा. कोण ही गर्दी!&lt;o:p&gt;&lt;/o:p&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;होकारार्थी वाक्य&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;ज्या वाक्यामधून होकार दर्शविला जातो त्यास&amp;nbsp;होकारार्थी वाक्य&amp;nbsp;किवा&amp;nbsp;करणरूपी वाक्य&amp;nbsp;म्हणतात. उदा. मी येत आहे.&lt;o:p&gt;&lt;/o:p&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;नकारार्थी वाक्य&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;ज्या वाक्यामधून नकार दर्शविला जातो त्यास&amp;nbsp;नकारार्थी वाक्य&amp;nbsp;असे म्हणतात. उदा. मी येणार नाही.&lt;o:p&gt;&lt;/o:p&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;वाक्यात असणार्&amp;zwj;या विधानांच्या संख्येवरून पडणारे प्रकार -&lt;/strong&gt;&lt;o:p&gt;&lt;/o:p&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;केवल&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;वाक्य&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;ज्या वाक्यामध्ये एकच उद्देश व एकच विधेय असते त्यास&amp;nbsp;केवल&amp;nbsp;वाक्य किवा शुद्ध वाक्य&amp;nbsp;असे म्हणतात. उदा. अविनाश टेबल टेनिस खेळतो.&lt;o:p&gt;&lt;/o:p&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;संयुक्त वाक्य&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जेव्हा वाक्यात दोन किवा अधिक केवल&amp;nbsp;वाक्य ही प्रधान सूचक उभयान्वयी अव्ययांनी जोडली जातात तेव्हा त्यास&amp;nbsp;संयुक्त&amp;nbsp;वाक्य&amp;nbsp;असे म्हणतात. उदा. देह जावो अथवा राहो.&lt;o:p&gt;&lt;/o:p&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;मिश्र वाक्य&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जेव्हा वाक्यात एक प्रधान वाक्य आणि एक किवा अधिक गौणवाक्य गौणत्वसूचक&amp;nbsp;उभयान्वयी&amp;nbsp;अव्ययांनी&amp;nbsp;जोडली जातात तेव्हा त्या वाक्यास मिश्र वाक्य असे म्हणतात. उदा. जो तळे राखील तो पाणी चाखील.&lt;o:p&gt;&lt;/o:p&gt;&lt;/p&gt;

&lt;p&gt;&lt;o:p&gt;&lt;/o:p&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;उत्तर -&lt;/strong&gt;&amp;nbsp;&lt;span style=&quot;&quot;&gt;चंद्रोदय =&amp;nbsp;&lt;strong&gt;चंद्र + उदय&lt;/strong&gt; हा योग्य विग्रह होईल.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;चंद्रोदय&amp;nbsp;&lt;/span&gt;हे&amp;nbsp;&lt;strong&gt;गुणादेश&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;स्वरसंधीचे&lt;/strong&gt;&amp;nbsp;उदाहरण आहे.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;चंद्रोदय =&amp;nbsp;चंद्र + उदय (अ + उ = ओ)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;गुणादेश स्वरसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;अ /आ + इ /&amp;nbsp;ई = ए,&amp;nbsp;अ /आ + उ / ऊ = ओ,&amp;nbsp;अ /आ + ऋ = अर&amp;nbsp; याप्रमाणे दोन वर्ण एकत्र येऊन&amp;nbsp;ए,&amp;nbsp;ओ,&amp;nbsp;अर असे बदल झाल्यास त्याला गुणादेश स्वरसंधी&amp;nbsp;म्हणतात.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;संधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जोडशब्द तयार करताना पहिल्या शब्दातील शेवटचा वर्ण व दुसऱ्या शब्दातील पहिला वर्ण हे एकमेकांमध्ये मिसळतात व त्या दोन्हीबद्दल एक वर्ण तयार होतो. वर्णाच्या अशा एकत्र होण्याच्या प्रकाराला&amp;nbsp;संधी&amp;nbsp;असे म्हणतात.&lt;/p&gt;

&lt;p&gt;संधीचे&amp;nbsp;&lt;strong&gt;तीन&lt;/strong&gt;&amp;nbsp;प्रकार आहेत.&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;स्वरसंधी&lt;/li&gt;
	&lt;li&gt;व्यंजनसंधी&lt;/li&gt;
	&lt;li&gt;विसर्गसंधी&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;strong&gt;स्वरसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकमेकांच्या शेजारी येणारे वर्ण हे जर स्वरांनी जोडले असतील तर त्यांना स्वरसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;स्वर + स्वर असे याचे&amp;nbsp;स्वरूप असते.​&amp;nbsp;उदा. विद्या + अर्थी = विद्यार्थी&amp;nbsp; (आ + अ = आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;व्यंजनसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जवळ जवळ येणाऱ्या या दोन वर्णांपैकी दोन्ही वर्ण व्यंजने असतील किंवा पहिला वर्ण व्यंजन व दुसरा वर्ण स्वर असेल तर त्याला व्यंजनसंधी असे म्हणतात.&lt;/p&gt;

&lt;p&gt;व्यंजन&amp;nbsp;+&amp;nbsp;व्यंजन&amp;nbsp;किंवा स्वर&amp;nbsp;असे त्याचे स्वरूप असते.&amp;nbsp;&amp;nbsp;उदा. सत्&amp;nbsp;+ आचार = सदाचार (त्&amp;nbsp;+&amp;nbsp;आ)&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;विसर्गसंधी&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एकत्र येणाऱ्या वर्णातील पहिला विसर्ग व दुसरा वर्ण व्यंजन किंवा स्वर असेल तर तेव्हा त्यास विसर्ग संधी असे म्हणतात.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;विसर्ग + व्यंजन किंवा विसर्ग + स्वर असे त्याचे स्वरूप असते. उदा. नि: + अंतर = निरंतर&lt;/p&gt;

&lt;div&gt;&lt;strong&gt;उत्तर-&lt;/strong&gt; केवल वाक्य&amp;nbsp;&lt;/div&gt;

&lt;div&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/div&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;एका वाक्यात किती विधाने असतात, त्यावरून वाक्यांचे तीन प्रकार मानले जातात.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;​१.केवल वाक्य २.मिश्र वाक्य ३.संयुक्त वाक्य&lt;/span&gt;&lt;/p&gt;

&lt;div&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/div&gt;

&lt;ul&gt;
	&lt;li&gt;
	&lt;div&gt;&lt;strong&gt;केवल वाक्य-&lt;/strong&gt; ज्या वाक्यात &lt;u&gt;एकच विधान &lt;/u&gt;असते म्हणजे &lt;u&gt;एकच उद्देश्य व एकच विधेय असते&lt;/u&gt;, त्या वाक्याला &amp;#39;केवल वाक्य&amp;#39; म्हणतात.&lt;/div&gt;
	&lt;/li&gt;
	&lt;li&gt;वर प्रश्नात दिलेल्या वाक्यात&amp;nbsp;&lt;span style=&quot;&quot;&gt;तो परीक्षेत उत्तीर्ण झाला &lt;/span&gt;&amp;nbsp;&amp;#39;तो&amp;#39; हे उद्देश्य आहे आणि &amp;#39;उत्तीर्ण झाला&amp;#39; हे विधेय आहे. म्हणजेच उद्देश्य आणि विधेय&amp;nbsp;हे एकच आहे म्हणून हे वाक्य &lt;strong&gt;&amp;#39;केवल वाक्य&amp;#39;&lt;/strong&gt; आहे.&lt;/li&gt;
&lt;/ul&gt;

संधीचे मुख्य ३ प्रकार पडतात.
&lt;ol&gt;
	&lt;li&gt;स्वर संधी&lt;/li&gt;
	&lt;li&gt;व्यंजन&amp;nbsp; संधी&lt;/li&gt;
	&lt;li&gt;विसर्ग संधी&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;स्वर संधी-&lt;/strong&gt; जवळ येणारे वर्ण जर स्वर असतील, तर त्यास &amp;lsquo;स्वरसंधी&amp;#39; असे म्हणतात.&lt;br /&gt;
&lt;strong&gt;उदा. &lt;/strong&gt;ग्रंथ + आलय = ग्रंथालय&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;स्वर संधीचेही बरेच प्रकार पडतात. त्यातीलच योग्य पर्याय असलेला प्रकार आपण पाहूयात.&lt;/li&gt;
	&lt;li&gt;स्वर संधीतील एक नियम असे सांगतो की &amp;#39;अ&amp;#39; किंवा &amp;lsquo;आ&amp;#39; पुढे &amp;lsquo;ए&amp;#39; किंवा &amp;lsquo;ऐ&amp;rsquo; स्वर आल्यास दोहोंबद्दल &amp;lsquo;ऐ&amp;rsquo; येतो, &amp;lsquo;ओ&amp;#39;&amp;nbsp; किंवा &amp;lsquo;औ&amp;rsquo; ह्र स्वर आल्यास दोहोंबद्दल &amp;lsquo;औ&amp;#39; येतो.&lt;/li&gt;
	&lt;li&gt;वन + औषधी यातील वन या शब्दातील &amp;#39;अ&amp;#39; व औषधी या शब्दातील &amp;#39;औ&amp;#39; यांची संधी होऊन दोहोंबद्दल &amp;#39;औ&amp;#39; येईल.&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अशाप्रकारे योग्य संधी&lt;strong&gt; वनौषधी (अ + औ = औ)&lt;/strong&gt; अशी होईल.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;br /&gt;
&lt;strong&gt;व्यंजन संधी -&lt;/strong&gt; व्यंजन + स्वर किंवा व्यंजन + व्यंजन असतात तेव्हा त्यांना व्यंजन संधी म्हणतात.&amp;nbsp;&lt;br /&gt;
&lt;strong&gt;उदा.&lt;/strong&gt; जगत् + नाथ = जगन्नाथ&lt;/p&gt;

&lt;p&gt;&lt;br /&gt;
&lt;strong&gt;विसर्ग संधी -&lt;/strong&gt; एकत्र येणाऱ्या वर्णातील पहिला&amp;nbsp; वर्ण विसर्ग व दुसरा वर्ण व्यंजन अथवा स्वर असेल तेव्हा त्यांना विसर्गसंधी म्हणतात.&amp;nbsp;&lt;br /&gt;
&lt;strong&gt;उदा. &lt;/strong&gt;उष: + काल = उष:काल&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;उत्तर -&lt;/strong&gt;&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;बसला&amp;nbsp;&lt;/span&gt;हे क्रियापदाचे भूतकाळी रूप आहे म्हणून&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;बसला&lt;/strong&gt;&amp;nbsp;&lt;/span&gt;या क्रियापदाचे आख्यातविकार&amp;nbsp;&lt;strong&gt;लाख्यात&lt;/strong&gt; हे होईल.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;आख्यात विकार&lt;/strong&gt;&amp;nbsp;- लिंग,&amp;nbsp;वचन व पुरुष यामुळे क्रियापदाच्या रुपात जो सात प्रकारे बदल होतो त्याला&amp;nbsp;आख्यात विकार असे म्हणतात कारण संस्कृतमध्ये क्रियापदाला आख्यात असे म्हणतात. व त्यात जो बदल होतो त्याला विकार असे म्हणतात.&amp;nbsp;उदा. बसतो, बसू, बसेल&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:320px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;काळ&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;क्रियापदाचे रूप&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;आख्याताचे नाव&lt;/strong&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;वर्तमानकाळ&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;बसतो&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;प्रथम -&amp;nbsp;ता -&amp;nbsp;आख्यात&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;भूतकाळ&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;बसला&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;ला -&amp;nbsp;आख्यात&lt;/strong&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;रीतीभूतकाळ&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;बसे&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;ई - आख्यात&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;भविष्यकाळ&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;बसेल&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;ईल - आख्यात&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;आज्ञार्थ&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;बसू&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;ऊ - आख्यात&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;विध्यर्थी&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;बसावा&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;वा - आख्यात&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;संकेतार्थ&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;बसता&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;द्वितीय -&amp;nbsp;ता - आख्यात&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&lt;strong&gt;उत्तर -&lt;/strong&gt;&amp;nbsp;निमंत्रण आले तर मी येईन.&amp;nbsp;&lt;span style=&quot;font-family: var(--bs-body-font-family); font-size: var(--bs-body-font-size); font-weight: var(--bs-body-font-weight); text-align: var(--bs-body-text-align);&quot;&gt;या वाक्यात&amp;nbsp;&lt;/span&gt;&lt;strong style=&quot;font-family: var(--bs-body-font-family); font-size: var(--bs-body-font-size); text-align: var(--bs-body-text-align);&quot;&gt;द्वितीय ताख्यात&lt;/strong&gt;&lt;span style=&quot;font-family: var(--bs-body-font-family); font-size: var(--bs-body-font-size); font-weight: var(--bs-body-font-weight); text-align: var(--bs-body-text-align);&quot;&gt;&amp;nbsp;आहे.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;वरील वाक्यातील&lt;/span&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;येईन&amp;nbsp;&lt;/span&gt;हे संकेतार्थी&amp;nbsp;क्रियापद आहे आणि&amp;nbsp;संकेतार्थी&amp;nbsp;क्रियापदांचा आख्यात&amp;nbsp;द्वितीय ताख्यात&amp;nbsp;असतो&amp;nbsp;म्हणून&amp;nbsp;या वाक्यातील आख्याताचे&amp;nbsp;नाव&amp;nbsp;द्वितीय ताख्यात&amp;nbsp;हे होईल.&lt;/p&gt;

&lt;p&gt;&lt;b&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;आख्यात विकार&lt;/span&gt;&lt;/b&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;&amp;nbsp;- &lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;लिंग&lt;/span&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;,&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;वचन व पुरुष यामुळे क्रियापदाच्या रुपात जो सात प्रकारे बदल होतो त्याला&lt;/span&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;आख्यात विकार असे म्हणतात कारण संस्कृतमध्ये क्रियापदाला&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;आख्यात असे म्हणतात. व त्यात जो बदल होतो त्याला विकार असे म्हणतात. उदा.&lt;/span&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;&amp;nbsp;येतो, यावा&lt;/span&gt;&lt;/p&gt;

